		local radius = math.sqrt(random:NextNumber()) * radius
		local angle = random:NextNumber(0, math.pi * 2)
		local x = point.X + radius * math.cos(angle)
		local z = point.Z + radius * math.sin(angle)

		return Vector3.new(x, point.Y, z)
	end,

	["VectorRandom"] = function(min: number, max: number): Vector3
		return Vector3.new(random:NextNumber(min, max), random:NextNumber(min, max), random:NextNumber(min, max))
