-- Track Internal
function TrackInternal:CalculateAverageVelocityForModel(Model)
	local totalVelocity = Vector3.new(0, 0, 0)
	local count = 0

	for _, Object in ipairs(Model:GetDescendants()) do
		if Object:IsA("BasePart") then
			totalVelocity = totalVelocity + Object.Velocity
			count = count + 1
		end
	end

	if count > 0 then
		return totalVelocity / count
	else
		return Vector3.new(0, 0, 0)
	end
end

function TrackInternal:CalculateSPSFromUnit(Measurement, Unit)
	return SPSCalculationTable[Unit] * Measurement
end

function TrackInternal:CalculatePositionFromOriginWithVelocity(TargetPosition: Vector3, TargetVelocity: Vector3, Origin: Vector3, Velocity: number)
	local Distance = (TargetPosition - Origin).Magnitude
	local TimeToTravel = Distance / Velocity

	return TargetPosition + (TargetVelocity * TimeToTravel)
end

