local function shopUIOpen()
	Shop.Enabled = true

	local buttons = Buttons:GetChildren()
	table.sort(buttons, function(a, b)
		if a:IsA("TextButton") and b:IsA("TextButton") then
			return a.LayoutOrder < b.LayoutOrder
		end

	end)

	local function tweenNextButton(index)
		local button = buttons[index]
		if button and button:IsA("TextButton") then
			local config = ButtonsConfig[button.Name]
			if config then
				local tween = TweenService:Create(button, TweenInfo.new(TIME_TO_TWEEN_SHOP, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), { Position = UDim2.new(unpack(config.Open)) })
				tween:Play()
				tween.Completed:Wait() -- Wait for the tween to complete before moving to the next button
			end
		end

		if index + 1 <= #buttons then
			tweenNextButton(index + 1) -- Recursively tween the next button
