local function GetTableType(t,Key,Value)
	assert(type(t) == "table", "Supplied argument is not a table")
	for i,_ in pairs(t) do
		if type(i) ~= "number" then
			return "Dictionary";
		end
	end

	if Key and Value then
		return "Dictionary";
	end

	return "Array";
end

