function TrackInternal:CalculateAverageVelocityForModel(Model)
	local totalVelocity = Vector3.new(0, 0, 0)
	local count = 0

	for _, Object in ipairs(Model:GetDescendants()) do
		if Object:IsA("BasePart") then
			totalVelocity = totalVelocity + Object.Velocity
			count = count + 1
		end
	end

	if count > 0 then
		return totalVelocity / count
	else
		return Vector3.new(0, 0, 0)
	end
end

